import { apiClient, unwrap } from '@linm-soft/common-components';
import type { BffResponse } from '@linm-soft/common-components';
import type { LedgerKind } from '../../constants/cashVoucherLedgerKind';

export interface VoucherRegistryDto {
  voucherTypeCode: string;
  name: string;
  nameEn?: string;
  ledgerKind: LedgerKind;
  idCodePrefix: string;
  sortOrder: number;
  isActive: boolean;
}

export interface ProcessingLevelDto {
  level: number;
  postCode?: string;
  name: string;
  nameEn?: string;
}

interface BffVoucherRegistryDto {
  voucherTypeCode: string;
  name: string;
  nameEn?: string;
  ledgerKind: string;
  idCodePrefix: string;
  sortOrder: number;
  isActive: boolean;
}

interface BffProcessingLevelDto {
  level: number;
  postCode?: string;
  name: string;
  nameEn?: string;
}

const registryCache = new Map<string, Promise<VoucherRegistryDto>>();
const levelsCache = new Map<string, Promise<ProcessingLevelDto[]>>();

const mapRegistry = (dto: BffVoucherRegistryDto): VoucherRegistryDto => ({
  voucherTypeCode: dto.voucherTypeCode,
  name: dto.name,
  nameEn: dto.nameEn,
  ledgerKind: dto.ledgerKind as LedgerKind,
  idCodePrefix: dto.idCodePrefix,
  sortOrder: dto.sortOrder,
  isActive: dto.isActive,
});

const fetchRegistry = async (voucherTypeCode: string): Promise<VoucherRegistryDto> => {
  const res = await apiClient.get<BffResponse<BffVoucherRegistryDto>>(
    `/system/voucher-registry/${encodeURIComponent(voucherTypeCode)}`,
  );
  return mapRegistry(unwrap(res));
};

const fetchProcessingLevels = async (ledgerKind: LedgerKind): Promise<ProcessingLevelDto[]> => {
  const res = await apiClient.get<BffResponse<BffProcessingLevelDto[]>>(
    `/system/processing-levels?ledgerKind=${encodeURIComponent(ledgerKind)}`,
  );
  return unwrap(res);
};

export const voucherRegistryService = {
  getByCode(voucherTypeCode: string): Promise<VoucherRegistryDto> {
    if (!registryCache.has(voucherTypeCode)) {
      registryCache.set(
        voucherTypeCode,
        fetchRegistry(voucherTypeCode).catch(err => {
          registryCache.delete(voucherTypeCode);
          return Promise.reject(err);
        }),
      );
    }
    return registryCache.get(voucherTypeCode)!;
  },

  getProcessingLevels(ledgerKind: LedgerKind): Promise<ProcessingLevelDto[]> {
    if (!levelsCache.has(ledgerKind)) {
      levelsCache.set(
        ledgerKind,
        fetchProcessingLevels(ledgerKind).catch(err => {
          levelsCache.delete(ledgerKind);
          return Promise.reject(err);
        }),
      );
    }
    return levelsCache.get(ledgerKind)!;
  },

  clearCache() {
    registryCache.clear();
    levelsCache.clear();
  },
};
